    const person = new RecordId("person", randomUUID());
    await surreal.query("CREATE $record CONTENT $content;", {
      record: identity,
      content: { name: "Ana", type: "human", role: "owner", workspace: workspaceRecord, created_at: now },
    });
    await surreal.query("CREATE $record CONTENT $content;", {
